import React, { useCallback, useEffect, useMemo, useState } from "react";
import { fetchIssLocation } from "../common/api";
import { IssContext } from "../common/context";

const POLL_INTERVAL_MS = 5000;

export function ThemeProvider({ children }) {
  const theme = useMemo(
    () => ({
      colors: {
        background:
          "radial-gradient(circle at 15% 20%, #1f2a44 0%, #0b1020 45%, #04070f 100%)",
        card: "rgba(11, 16, 32, 0.82)",
        text: "#e2e8f0",
        muted: "#94a3b8",
        border: "#2b3754",
      },
    }),
    []
  );

  return (
    <div
      style={{
        minHeight: "100vh",
        background: theme.colors.background,
        color: theme.colors.text,
        fontFamily: "Segoe UI, Tahoma, Geneva, Verdana, sans-serif",
        paddingBottom: "20px",
      }}
    >
      {children}
    </div>
  );
}

export function IssProvider({ children }) {
  const [position, setPosition] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [lastUpdated, setLastUpdated] = useState(null);

  const refresh = useCallback(async () => {
    try {
      const data = await fetchIssLocation();
      setPosition({
        latitude: Number(data.latitude),
        longitude: Number(data.longitude),
        altitude: Number(data.altitude),
        velocity: Number(data.velocity),
      });
      setLastUpdated(new Date());
      setError("");
    } catch (err) {
      setError(err.message || "Unable to load ISS location.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    refresh();

    const intervalId = setInterval(refresh, POLL_INTERVAL_MS);
    return () => clearInterval(intervalId);
  }, [refresh]);

  const contextValue = useMemo(
    () => ({
      position,
      loading,
      error,
      lastUpdated,
      refresh,
    }),
    [position, loading, error, lastUpdated, refresh]
  );

  return <IssContext.Provider value={contextValue}>{children}</IssContext.Provider>;
}

export default function AppWrapper({ children }) {
  return (
    <main
      style={{
        maxWidth: "980px",
        margin: "0 auto",
        padding: "20px",
      }}
    >
      {children}
    </main>
  );
}
